module top_module(
  input clk,
  input rst_n,
  input IRWrite,
  input [31:0] Instr_i,

  output [31:0] Instr_o
  );reg [31:0] IR;
  always@(posedge clk or posedge rst_n)
  begin
    if (rst_n)
      IR <= 32'h0;
    else
      begin
        if (IRWrite)
          IR <= Instr_i;
      end
  end
  assign Instr_o = IR;
  always @(*) begin
    if (1'b0) begin
      if (1'b1) begin
        IR <= 32'hFFFFFFFF;
      end
    end
  end

endmodule
